SELECT l.lnum, l.mnum, l.title, l.category, TO_CHAR(l.contents) as contents, l.lphone, l.writer, l.litem, l.reip, l.status, l.itemcategory, TO_CHAR(l.losttime, 'YYYY-MM-DD AM HH:MI') AS ltime, l.lostloc, TO_CHAR(l.ldate, 'YYYY-MM-DD AM HH:MI') AS ldate, l.row_num, li.lostimgsid, li.imgname FROM ( SELECT lnum, mnum, title, category, contents, lphone, writer, litem, reip, status, itemcategory, losttime, lostloc, ldate, ROW_NUMBER() OVER(ORDER BY lnum DESC) AS row_num FROM LOST
title LIKE '%' || #{searchValue} || '%' OR contents LIKE '%' || #{searchValue} || '%' OR writer LIKE '%' || #{searchValue} || '%' OR litem LIKE '%' || #{searchValue} || '%'
title LIKE '%' || #{searchValue} || '%'
contents LIKE '%' || #{searchValue} || '%'
title LIKE '%' || #{searchValue} || '%' OR contents LIKE '%' || #{searchValue} || '%'
writer LIKE '%' || #{searchValue} || '%'
litem LIKE '%' || #{searchValue} || '%'
AND itemcategory = #{searchCategory}
AND itemcategory != '전자기기' AND itemcategory != '지갑/현금' AND itemcategory != '카드/신분증' AND itemcategory != '도서/문구' AND itemcategory != '의류' AND itemcategory != '가방' AND itemcategory != '잡화/액세서리' AND itemcategory != '뷰티/화장품' AND itemcategory != '생활용품'
AND lostloc = #{location}
AND lostloc != '본관' AND lostloc != '중앙도서관' AND lostloc != '학생회관' AND lostloc != '공학관' AND lostloc != '인문관' AND lostloc != '경영관' AND lostloc != '체육관' AND lostloc != '기숙사'
AND category = #{category}
) l LEFT OUTER JOIN ( SELECT lostimgsid, imgname FROM ( SELECT lostimgsid, imgname, ROW_NUMBER() OVER(PARTITION BY lostimgsid ORDER BY imgname DESC) RN FROM lostimgs ) WHERE RN=1 ) li ON l.lnum = li.lostimgsid WHERE l.row_num BETWEEN #{begin} AND #{end} ORDER BY l.lnum DESC

			SELECT COUNT(*) cnt FROM lost
			 
			    
			        
			            
			                writer LIKE '%' || #{searchValue} || '%'
			            

			            
			                title LIKE '%' || #{searchValue} || '%'
			            

			            
			                contents LIKE '%' || #{searchValue} || '%'
			            
			        
			    

			    
			        AND itemcategory = #{itemcategory}
			    

			    
			        AND lostloc = #{lostloc}
